import pyncm
import datetime

# pip install pyncm
# https://github.com/mos9527/pyncm
from pyncm import apis, SetCurrentSession


MUSIC_U = ""
PLAYLIST_ID = "2584370810"
OUTPUT_PATH = "my_music_dataset.csv"

session = pyncm.Session()
session.cookies.set("MUSIC_U", MUSIC_U)
SetCurrentSession(session)
result = apis.playlist.GetPlaylistInfo(PLAYLIST_ID)

first_track = result['playlist']['trackIds'][0]
at = first_track['at']
print(datetime.datetime.fromtimestamp(at / 1000))
